265→async function insertSnapshotRows(rows: SnapshotRow[]): Promise<number> {
266→  if (rows.length === 0) return 0;
267→  const batchSize = 200;
268→  let inserted = 0;
269→  for (let i = 0; i < rows.length; i += batchSize) {
270→    const batch = rows.slice(i, i + batchSize);
271→    const values: unknown[] = [];
272→    const placeholders = batch.map((row, idx) => {
273→      const base = idx * 13;
274→      values.push(
275→        row.snapshotDate,
276→        row.verticalId,
277→        row.pointId,
278→        row.category,
279→        row.siteName,
280→        row.latitude,
281→        row.longitude,
282→        JSON.stringify(row.details),
283→        row.gaps,
284→        row.eventsCount,
285→        row.photoUrl,
286→        row.source,
287→        row.externalId,
288→      );
289→      return `($${base + 1},$${base + 2},$${base + 3},$${base + 4},$${base + 5},$${base + 6},$${base + 7},$${base + 8},$${base + 9},$${base + 10},$${base + 11},$${base + 12},$${base + 13})`;
290→    });
291→    const result = await query(
292→      `INSERT INTO snapshots (snapshot_date, vertical_id, point_id, category, site_name, latitude, longitude, details, gaps, events_count, photo_url, source, external_id)
293→       VALUES ${placeholders.join(",")}
294→       ON CONFLICT (snapshot_date, point_id) DO NOTHING`,
295→      values,
296→    );
297→    inserted += result.rowCount ?? 0;
298→  }
299→  return inserted;
300→}
