476→export interface SnapshotResult {
477→  snapshotDate: string;
478→  snapshotsInserted: number;
479→  deltasInserted: number;
480→  statsComputed: number;
481→  baselineDate: string | null;
482→}
483→
484→export async function runWeeklySnapshot(
485→  dateOverride?: string,
486→): Promise<SnapshotResult> {
487→  const snapshotDate =
488→    dateOverride ?? new Date().toISOString().slice(0, 10);
489→
490→  // Step 1: build current projection
491→  const [pointEvents, legacySubs] = await Promise.all([
492→    getPointEvents(),
493→    getLegacySubmissions(),
494→  ]);
495→  const allEvents = mergePointEventsWithLegacy(pointEvents, legacySubs);
496→  const projectedPoints = projectPointsFromEvents(allEvents);
497→
498→  // Step 2: build snapshot rows
499→  const snapshotRows = buildSnapshotRows(snapshotDate, projectedPoints);
500→
501→  // Step 3: insert snapshots
502→  const snapshotsInserted = await insertSnapshotRows(snapshotRows);
503→
504→  // Step 4: compute deltas
505→  const baselineDate = await getPreviousSnapshotDate(snapshotDate);
506→  let deltasInserted = 0;
507→
508→  const currentMap = new Map<string, ProjectedPoint>();
509→  for (const p of projectedPoints) currentMap.set(p.pointId, p);
510→
511→  let deltasByVertical = new Map<string, { new: number; removed: number; changed: number; unchanged: number }>();
512→
513→  if (baselineDate) {
514→    const previousMap = await loadSnapshotAsMap(baselineDate);
515→    const deltas = computeDeltas(
516→      currentMap,
517→      previousMap,
518→      snapshotDate,
519→      baselineDate,
520→    );
521→    deltasInserted = await insertDeltaRows(deltas);
522→
523→    // Aggregate delta counts by vertical
524→    for (const d of deltas) {
525→      const counts = deltasByVertical.get(d.verticalId) ?? {
526→        new: 0,
527→        removed: 0,
528→        changed: 0,
529→        unchanged: 0,
530→      };
531→      if (d.deltaType === "new") counts.new++;
532→      else if (d.deltaType === "removed") counts.removed++;
533→      else if (d.deltaType === "changed") counts.changed++;
534→      else if (d.deltaType === "unchanged") counts.unchanged++;
535→      deltasByVertical.set(d.verticalId, counts);
536→    }
537→  }
538→
539→  // Step 5: compute stats per vertical
540→  const verticalGroups = new Map<string, ProjectedPoint[]>();
541→  for (const p of projectedPoints) {
542→    const list = verticalGroups.get(p.category) ?? [];
543→    list.push(p);
544→    verticalGroups.set(p.category, list);
545→  }
546→
547→  // Also include verticals with 0 current points but deltas (removed points)
548→  for (const vid of deltasByVertical.keys()) {
549→    if (!verticalGroups.has(vid)) verticalGroups.set(vid, []);
550→  }
551→
552→  let statsComputed = 0;
553→
554→  for (const [verticalId, points] of verticalGroups) {
555→    const totalPoints = points.length;
556→    const completedPoints = points.filter((p) => p.gaps.length === 0).length;
557→    const completionRate =
558→      totalPoints > 0
559→        ? Math.round((completedPoints / totalPoints) * 10000) / 100
560→        : 0;
561→
562→    const dc = deltasByVertical.get(verticalId) ?? {
563→      new: 0,
564→      removed: 0,
565→      changed: 0,
566→      unchanged: 0,
567→    };
568→
569→    // Average price for fuel verticals
570→    let avgPrice: number | null = null;
571→    if (verticalId === "fuel_station") {
572→      const prices = points
573→        .map((p) => p.details.fuelPrice)
574→        .filter((v): v is number => typeof v === "number" && v > 0);
575→      if (prices.length > 0) {
576→        avgPrice =
577→          Math.round(
578→            (prices.reduce((a, b) => a + b, 0) / prices.length) * 100,
579→          ) / 100;
580→      }
581→    }
582→
583→    // Historical data for trends
584→    const history = await getHistoricalStats(verticalId, snapshotDate, 8);
585→    const histTotalPoints = history.map((h) => h.total_points);
586→    const histNewCount = history.map((h) => h.new_count);
587→    const histRemovedCount = history.map((h) => h.removed_count);
588→
589→    // Week-over-week growth
590→    let weekOverWeekGrowth: number | null = null;
591→    if (history.length > 0 && history[0].total_points > 0) {
592→      weekOverWeekGrowth =
593→        Math.round(
594→          ((totalPoints - history[0].total_points) /
595→            history[0].total_points) *
596→            10000,
597→        ) / 100;
598→    }
599→
600→    // Moving average (4-week)
601→    const movingAvg4w = computeMovingAverage(
602→      [...histTotalPoints.reverse(), totalPoints],
603→      4,
604→    );
605→
606→    // Z-scores
607→    const zScoreTotalPoints = computeZScore(totalPoints, histTotalPoints);
608→    const zScoreNewCount = computeZScore(dc.new, histNewCount);
609→    const zScoreRemovedCount = computeZScore(dc.removed, histRemovedCount);
610→
611→    // Anomaly detection
612→    const anomalyFlags: AnomalyFlag[] = [];
613→    const a1 = detectAnomalies(totalPoints, histTotalPoints, "total_points");
614→    if (a1) anomalyFlags.push(a1);
615→    const a2 = detectAnomalies(dc.new, histNewCount, "new_count");
616→    if (a2) anomalyFlags.push(a2);
617→    const a3 = detectAnomalies(dc.removed, histRemovedCount, "removed_count");
618→    if (a3) anomalyFlags.push(a3);
619→
620→    await upsertStatsRow({
621→      snapshotDate,
622→      verticalId,
623→      totalPoints,
624→      completedPoints,
625→      completionRate,
626→      newCount: dc.new,
627→      removedCount: dc.removed,
628→      changedCount: dc.changed,
629→      unchangedCount: dc.unchanged,
630→      avgPrice,
631→      weekOverWeekGrowth,
632→      movingAvg4w: movingAvg4w !== null ? Math.round(movingAvg4w * 100) / 100 : null,
633→      zScoreTotalPoints: zScoreTotalPoints !== null ? Math.round(zScoreTotalPoints * 100) / 100 : null,
634→      zScoreNewCount: zScoreNewCount !== null ? Math.round(zScoreNewCount * 100) / 100 : null,
635→      zScoreRemovedCount: zScoreRemovedCount !== null ? Math.round(zScoreRemovedCount * 100) / 100 : null,
636→      anomalyFlags,
637→    });
638→    statsComputed++;
639→  }
640→
641→  return {
642→    snapshotDate,
643→    snapshotsInserted,
644→    deltasInserted,
645→    statsComputed,
646→    baselineDate,
647→  };
648→}
