 47→function toQueueErrorInfo(error: unknown): { message: string; retryable: boolean } {
 48→  const fallback = 'Unable to sync queued submission';
 49→  if (error instanceof Error) {
 50→    const withRetryable = error as Error & { retryable?: unknown };
 51→    const retryable = typeof withRetryable.retryable === 'boolean' ? withRetryable.retryable : true;
 52→    const message = error.message?.trim() || fallback;
 53→    return { message, retryable };
 54→  }
 55→  return { message: String(error ?? fallback), retryable: true };
 56→}
