528→export async function extractPhotoMetadataFromUrl(photoUrl: string): Promise<ExtractedPhotoMetadata | null> {
529→  if (!photoUrl || !isHttpUrl(photoUrl)) return null;
530→
531→  const source: ExtractPhotoMetadataSource = "remote_url";
532→  const controller = new AbortController();
533→  const timeout = setTimeout(() => controller.abort(), REMOTE_FETCH_TIMEOUT_MS);
534→  try {
535→    const response = await fetch(photoUrl, { signal: controller.signal });
536→    const mime = normalizeString(response.headers.get("content-type"));
537→    const ext = inferRemoteExt(photoUrl);
538→    if (!response.ok) {
539→      return createExtractedPhotoMetadata(
540→        "parse_error",
541→        withContext(`Unable to fetch remote photo for EXIF recovery (HTTP ${response.status})`, { source, mime, ext }),
542→        source,
543→      );
544→    }
545→    const arrayBuffer = await response.arrayBuffer();
546→    const byteLength = arrayBuffer.byteLength;
547→    if (!byteLength) {
548→      return createExtractedPhotoMetadata(
549→        "missing",
550→        withContext("Remote photo is empty; EXIF recovery skipped", { source, mime, ext, byteLength }),
551→        source,
552→      );
553→    }
554→    if (byteLength > MAX_REMOTE_METADATA_BYTES) {
555→      return createExtractedPhotoMetadata(
556→        "parse_error",
557→        withContext(`Remote photo exceeds EXIF fetch limit (${MAX_REMOTE_METADATA_BYTES} bytes)`, {
558→          source,
559→          mime,
560→          ext,
561→          byteLength,
562→        }),
563→        source,
564→      );
565→    }
566→    return await extractPhotoMetadata(Buffer.from(arrayBuffer), { source, mime, ext, byteLength });
567→  } catch (error) {
568→    const timeoutMessage = error instanceof Error && error.name === "AbortError";
569→    const reason = timeoutMessage
570→      ? `Timed out fetching remote photo after ${REMOTE_FETCH_TIMEOUT_MS}ms`
571→      : "Unable to fetch remote photo for EXIF recovery";
572→    return createExtractedPhotoMetadata("parse_error", withContext(reason, { source, ext: inferRemoteExt(photoUrl) }), source);
573→  } finally {
574→    clearTimeout(timeout);
575→  }
576→}
577→
578→export function applyClientExifFallback(
579→  metadata: ExtractedPhotoMetadata,
580→  clientExif: ClientExifData | null | undefined,
581→): ExtractedPhotoMetadata {
582→  if (!clientExif) return metadata;
583→  if (hasExifSignal(metadata)) return metadata;
584→
585→  const gps: SubmissionLocation | null =
586→    typeof clientExif.latitude === "number" &&
587→    typeof clientExif.longitude === "number" &&
588→    Number.isFinite(clientExif.latitude) &&
589→    Number.isFinite(clientExif.longitude)
590→      ? { latitude: clientExif.latitude, longitude: clientExif.longitude }
591→      : null;
592→
593→  const capturedAt = typeof clientExif.capturedAt === "string" && clientExif.capturedAt.trim() ? clientExif.capturedAt.trim() : null;
594→  const deviceMake = typeof clientExif.deviceMake === "string" && clientExif.deviceMake.trim() ? clientExif.deviceMake.trim() : null;
595→  const deviceModel = typeof clientExif.deviceModel === "string" && clientExif.deviceModel.trim() ? clientExif.deviceModel.trim() : null;
596→
597→  if (!gps && !capturedAt && !deviceMake && !deviceModel) return metadata;
598→
599→  return {
600→    gps,
601→    capturedAt,
602→    deviceMake,
603→    deviceModel,
604→    exifStatus: "fallback_recovered",
605→    exifReason: `EXIF recovered from client-side extraction (server got ${metadata.exifStatus}: ${metadata.exifReason ?? "no details"})`,
606→    exifSource: "upload_buffer",
607→  };
608→}
