 23→interface WindowWithIdleCallback extends Window {
 24→  requestIdleCallback?: (callback: IdleRequestCallback, options?: IdleRequestOptions) => number;
 25→  cancelIdleCallback?: (handle: number) => void;
 26→}
 27→
 28→const App: React.FC = () => {
 29→  const isSyncingRef = useRef(false);
 30→  const [currentScreen, setCurrentScreen] = useState<Screen>(Screen.SPLASH);
 31→  const [selectedPoint, setSelectedPoint] = useState<DataPoint | null>(null);
 32→  const [isOffline, setIsOffline] = useState(false);
 33→  const [isAuthenticated, setIsAuthenticated] = useState(false);
 34→  const [isAdmin, setIsAdmin] = useState(false);
 35→  const [language, setLanguage] = useState<'en' | 'fr'>(() => {
 36→    const saved = localStorage.getItem('adl_language');
 37→    return saved === 'en' ? 'en' : 'fr';
 38→  });
 39→  const [history, setHistory] = useState<Screen[]>([]);
 40→  const [authReturnScreen, setAuthReturnScreen] = useState<Screen>(Screen.SPLASH);
 41→  const [contributionMode, setContributionMode] = useState<ContributionMode>('CREATE');
 42→  const [contributionPoint, setContributionPoint] = useState<DataPoint | null>(null);
 43→  const t = (en: string, fr: string) => (language === 'fr' ? fr : en);
 44→
 45→  const navigateTo = (screen: Screen, point: DataPoint | null = null) => {
 46→    if (currentScreen === Screen.SPLASH && screen !== Screen.SPLASH) {
 47→      localStorage.setItem("adl_splash_seen", "true");
 48→    }
 49→    if (screen === Screen.AUTH) {
 50→      setAuthReturnScreen(currentScreen);
 51→    }
 52→    setHistory(prev => [...prev, currentScreen]);
 53→    setCurrentScreen(screen);
 54→    if (point) setSelectedPoint(point);
 55→  };
 56→
 57→  const goBack = () => {
 58→    if (history.length > 0) {
 59→      const prev = history[history.length - 1];
 60→      setHistory(prevHistory => prevHistory.slice(0, -1));
 61→      setCurrentScreen(prev);
 62→      return;
 63→    }
 64→    if (currentScreen === Screen.AUTH) {
 65→      setCurrentScreen(authReturnScreen);
 66→      return;
 67→    }
 68→    // Fallback for screens opened via tab navigation (no history).
 69→    setHistory([]);
 70→    setCurrentScreen(Screen.HOME);
 71→  };
 72→
 73→  const switchTab = (screen: Screen) => {
 74→    setHistory([]);
 75→    if (screen === Screen.CONTRIBUTE && !isAuthenticated) {
 76→      setAuthReturnScreen(currentScreen);
 77→      setCurrentScreen(Screen.AUTH);
 78→    } else {
 79→      if (screen === Screen.AUTH) {
 80→        setAuthReturnScreen(currentScreen);
 81→      }
 82→      if (screen === Screen.CONTRIBUTE) {
 83→        setContributionMode('CREATE');
 84→        setContributionPoint(null);
 85→      }
 86→      setCurrentScreen(screen);
 87→    }
 88→  };
 89→
 90→  const openContribution = (mode: ContributionMode, point: DataPoint | null = null) => {
 91→    setContributionMode(mode);
 92→    setContributionPoint(point);
 93→    if (isAuthenticated) {
 94→      navigateTo(Screen.CONTRIBUTE);
 95→      return;
 96→    }
 97→    navigateTo(Screen.AUTH);
 98→  };
 99→
100→  useEffect(() => {
101→    localStorage.setItem('adl_language', language);
102→    document.documentElement.lang = language;
103→  }, [language]);
104→
105→  useEffect(() => {
106→    const handleStatus = async () => {
107→      const online = navigator.onLine;
108→      setIsOffline(!online);
109→      if (online) {
110→        const runSync = async () => {
111→          if (isSyncingRef.current) return;
112→          isSyncingRef.current = true;
113→          try {
114→            await flushOfflineQueue(sendSubmissionPayload);
115→          } catch (error) {
116→            console.error('[App] Offline queue sync failed:', error);
117→          } finally {
118→            isSyncingRef.current = false;
119→          }
120→        };
121→        const windowWithIdle = window as WindowWithIdleCallback;
122→        if (typeof windowWithIdle.requestIdleCallback === 'function') {
123→          windowWithIdle.requestIdleCallback(() => {
124→            void runSync();
125→          }, { timeout: 2000 });
126→        } else {
127→          window.setTimeout(() => {
128→            void runSync();
129→          }, 0);
130→        }
131→      }
132→    };
133→    window.addEventListener('online', handleStatus);
134→    window.addEventListener('offline', handleStatus);
135→    void handleStatus();
136→    return () => {
137→      window.removeEventListener('online', handleStatus);
138→      window.removeEventListener('offline', handleStatus);
139→    };
140→  }, []);
141→
142→  const refreshSession = async () => {
143→    const session = await getSession();
144→    const hasUser = !!session?.user;
145→    setIsAuthenticated(hasUser);
146→    setIsAdmin(Boolean(session?.user?.isAdmin));
147→    return hasUser;
148→  };
149→
150→  useEffect(() => {
151→    const bootstrap = async () => {
152→      const hasUser = await refreshSession();
153→      const hasSeenSplash = localStorage.getItem("adl_splash_seen") === "true";
154→      if (currentScreen === Screen.SPLASH && (hasUser || hasSeenSplash)) {
155→        setHistory([]);
156→        setCurrentScreen(Screen.HOME);
157→      }
158→    };
159→    bootstrap();
160→  }, []);
161→
162→  useEffect(() => {
163→    const hasSeenSplash = localStorage.getItem("adl_splash_seen") === "true";
164→    if (currentScreen === Screen.SPLASH && hasSeenSplash) {
165→      setHistory([]);
166→      setCurrentScreen(Screen.HOME);
167→    }
168→  }, [currentScreen]);
169→
170→  const renderScreen = () => {
171→    switch (currentScreen) {
172→      case Screen.SPLASH:
173→        return <Splash onStart={(scr) => navigateTo(scr)} language={language} />;
174→      case Screen.HOME:
175→        return (
176→          <Home
177→            onSelectPoint={(p) => navigateTo(Screen.DETAILS, p)}
178→            isAuthenticated={isAuthenticated}
179→            isAdmin={isAdmin}
180→            onAuth={() => navigateTo(Screen.AUTH)}
181→            onContribute={() => openContribution('CREATE')}
182→            onProfile={() => switchTab(Screen.PROFILE)}
183→            language={language}
184→          />
185→        );
186→      case Screen.DETAILS:
187→        return (
188→          <Details
189→            point={selectedPoint}
190→            onBack={goBack}
191→            onEnrich={() => openContribution('ENRICH', selectedPoint)}
192→            onAddNew={() => openContribution('CREATE')}
193→            isAuthenticated={isAuthenticated}
194→            onAuth={() => navigateTo(Screen.AUTH)}
195→            language={language}
196→          />
197→        );
198→      case Screen.AUTH:
199→        return <Auth language={language} onBack={goBack} onComplete={async () => { await refreshSession(); switchTab(Screen.HOME); }} />;
200→      case Screen.CONTRIBUTE:
201→        return (
202→          <ContributionFlow
203→            language={language}
204→            onBack={goBack}
205→            onComplete={() => switchTab(Screen.HOME)}
206→            mode={contributionMode}
207→            seedPoint={contributionPoint}
208→          />
209→        );
210→      case Screen.PROFILE:
211→        return <Profile language={language} onBack={goBack} onSettings={() => navigateTo(Screen.SETTINGS)} onRedeem={() => navigateTo(Screen.REWARDS)} />;
212→      case Screen.ANALYTICS:
213→        return (
214→          <Analytics
215→            onBack={goBack}
216→            isAdmin={isAdmin}
217→            onAdmin={isAdmin ? () => navigateTo(Screen.ADMIN) : undefined}
218→            onDeltaDashboard={isAdmin ? () => navigateTo(Screen.DELTA_DASHBOARD) : undefined}
219→            language={language}
220→          />
221→        );
222→      case Screen.SETTINGS:
223→        return (
224→          <Settings
225→            onBack={goBack}
226→            language={language}
227→            onLanguageChange={setLanguage}
228→            onLogout={async () => {
229→              try {
230→                await signOut();
231→              } catch {
232→                // Fallback to local logout even if server sign-out fails.
233→              } finally {
234→                await refreshSession();
235→                setIsAuthenticated(false);
236→                switchTab(Screen.SPLASH);
237→              }
238→            }}
239→          />
240→        );
241→      case Screen.QUALITY:
242→        return <QualityInfo language={language} onBack={goBack} />;
243→      case Screen.REWARDS:
244→        return <RewardsCatalog language={language} onBack={goBack} />;
245→      case Screen.ADMIN:
246→        return <AdminQueue language={language} onBack={goBack} />;
247→      case Screen.DELTA_DASHBOARD:
248→        return <DeltaDashboard language={language} onBack={goBack} />;
249→      default:
250→        return <Splash onStart={(scr) => navigateTo(scr)} language={language} />;
251→    }
252→  };
253→
254→  return (
255→    <ErrorBoundary>
256→    <div className="app-shell flex flex-col w-full max-w-md mx-auto bg-white shadow-2xl relative overflow-hidden border-x border-gray-100">
257→      {isOffline && (
258→        <div className="bg-amber-600 text-white text-[10px] font-bold py-1.5 px-4 text-center z-50 tracking-widest uppercase">
259→          {t('Offline Mode • Local Sync Active', 'Mode hors ligne • Sync locale active')}
260→        </div>
261→      )}
262→
263→      <main className="flex-1 overflow-hidden relative">
264→        <Suspense
265→          fallback={
266→            <div className="h-full w-full bg-[#f9fafb] p-4">
267→              <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm text-xs text-gray-500">
268→                {t('Loading screen...', 'Chargement de l\'ecran...')}
269→              </div>
270→            </div>
271→          }
272→        >
273→          {renderScreen()}
274→        </Suspense>
275→      </main>
276→
277→      {!([Screen.SPLASH, Screen.AUTH, Screen.CONTRIBUTE].includes(currentScreen)) && (
278→        <Navigation
279→          currentScreen={currentScreen}
280→          onNavigate={(scr) => switchTab(scr)}
281→          isAuthenticated={isAuthenticated}
282→          isAdmin={isAdmin}
283→          language={language}
284→        />
285→      )}
286→    </div>
287→    </ErrorBoundary>
