 59→const DeltaDashboard: React.FC<Props> = ({ onBack, language }) => {
 60→  const t = (en: string, fr: string) => (language === 'fr' ? fr : en);
 61→
 62→  const [selectedVertical, setSelectedVertical] = useState<string>('all');
 63→  const [stats, setStats] = useState<StatsRow[]>([]);
 64→  const [anomalies, setAnomalies] = useState<AnomalyRow[]>([]);
 65→  const [trendData, setTrendData] = useState<TrendDataPoint[]>([]);
 66→  const [recentDeltas, setRecentDeltas] = useState<DeltaRow[]>([]);
 67→  const [loading, setLoading] = useState(true);
 68→
 69→  // Load stats and anomalies on mount
 70→  useEffect(() => {
 71→    const load = async () => {
 72→      try {
 73→        setLoading(true);
 74→        const [statsData, anomalyData] = await Promise.all([
 75→          apiJson<StatsRow[]>('/api/analytics?view=snapshots?limit=52'),
 76→          apiJson<AnomalyRow[]>('/api/analytics?view=anomalies'),
 77→        ]);
 78→        setStats(Array.isArray(statsData) ? statsData : []);
 79→        setAnomalies(Array.isArray(anomalyData) ? anomalyData : []);
 80→      } catch {
 81→        setStats([]);
 82→        setAnomalies([]);
 83→      } finally {
 84→        setLoading(false);
 85→      }
 86→    };
 87→    void load();
 88→  }, []);
 89→
 90→  // Load trends and deltas when vertical changes
 91→  useEffect(() => {
 92→    const loadVerticalData = async () => {
 93→      if (selectedVertical === 'all') {
 94→        setTrendData([]);
 95→        setRecentDeltas([]);
 96→        return;
 97→      }
 98→      try {
 99→        const [trend, deltasResp] = await Promise.all([
100→          apiJson<{ data: TrendDataPoint[] }>(`/api/analytics?view=trends&vertical=${selectedVertical}&metric=total_points&weeks=12`),
101→          apiJson<{ deltas: DeltaRow[] }>(`/api/analytics?view=deltas&vertical=${selectedVertical}&limit=20`),
102→        ]);
103→        setTrendData(Array.isArray(trend?.data) ? trend.data : []);
104→        setRecentDeltas(Array.isArray(deltasResp?.deltas) ? deltasResp.deltas : []);
105→      } catch {
106→        setTrendData([]);
107→        setRecentDeltas([]);
108→      }
109→    };
110→    void loadVerticalData();
111→  }, [selectedVertical]);
112→
113→  // Derived data
114→  const filteredStats = selectedVertical === 'all'
115→    ? stats
116→    : stats.filter((s) => s.vertical_id === selectedVertical);
117→
118→  const latestStats = filteredStats.length > 0 ? filteredStats[0] : null;
119→
120→  const latestDate = stats.length > 0 ? stats[0].snapshot_date : null;
121→
122→  // Aggregate summary for "all" view
123→  const summaryTotalPoints = selectedVertical === 'all'
124→    ? stats.filter((s) => s.snapshot_date === latestDate).reduce((sum, s) => sum + s.total_points, 0)
125→    : latestStats?.total_points ?? 0;
126→
127→  const summaryWoW = latestStats?.week_over_week_growth ?? null;
128→  const summaryCompletion = latestStats?.completion_rate ?? 0;
129→
130→  // Delta breakdown for stacked bar chart
131→  const deltaBreakdown = (() => {
132→    if (selectedVertical === 'all') {
133→      // Aggregate per date
134→      const byDate = new Map<string, { date: string; new: number; removed: number; changed: number; unchanged: number }>();
135→      for (const s of stats) {
136→        const existing = byDate.get(s.snapshot_date) ?? { date: s.snapshot_date, new: 0, removed: 0, changed: 0, unchanged: 0 };
137→        existing.new += s.new_count;
138→        existing.removed += s.removed_count;
139→        existing.changed += s.changed_count;
140→        existing.unchanged += s.unchanged_count;
141→        byDate.set(s.snapshot_date, existing);
142→      }
143→      return [...byDate.values()].sort((a, b) => a.date.localeCompare(b.date)).slice(-12);
144→    }
145→    return filteredStats
146→      .map((s) => ({
147→        date: s.snapshot_date,
148→        new: s.new_count,
149→        removed: s.removed_count,
150→        changed: s.changed_count,
151→        unchanged: s.unchanged_count,
152→      }))
153→      .reverse()
154→      .slice(-12);
155→  })();
156→
157→  // Price trend (fuel only)
158→  const showPriceTrend = selectedVertical === 'fuel_station';
159→  const priceTrend = showPriceTrend
160→    ? filteredStats
161→        .filter((s) => s.avg_price !== null)
162→        .map((s) => ({ date: s.snapshot_date, price: s.avg_price! }))
163→        .reverse()
164→        .slice(-12)
165→    : [];
166→
167→  // Active verticals (those with stats)
168→  const activeVerticals = [...new Set(stats.map((s) => s.vertical_id))];
169→
170→  const deltaTypeColor = (type: string) => {
171→    switch (type) {
172→      case 'new': return 'text-green-600 bg-green-50';
173→      case 'removed': return 'text-red-600 bg-red-50';
174→      case 'changed': return 'text-amber-600 bg-amber-50';
175→      default: return 'text-gray-500 bg-gray-50';
176→    }
177→  };
178→
179→  const deltaTypeLabel = (type: string) => {
180→    switch (type) {
181→      case 'new': return t('NEW', 'NOUVEAU');
182→      case 'removed': return t('REMOVED', 'SUPPRIME');
183→      case 'changed': return t('CHANGED', 'MODIFIE');
184→      default: return t('UNCHANGED', 'INCHANGE');
185→    }
186→  };
187→
188→  return (
189→    <div className="flex flex-col h-full bg-[#f9fafb] overflow-y-auto no-scrollbar">
190→      {/* Header */}
191→      <div className="sticky top-0 z-30 bg-white border-b border-gray-100 px-4 h-14 flex items-center">
192→        <button onClick={onBack} className="p-2 -ml-2 text-gray-700 hover:text-[#0f2b46] transition-colors">
193→          <ArrowLeft size={20} />
194→        </button>
195→        <h3 className="text-sm font-bold mx-auto">{t('Delta Intelligence', 'Intelligence Delta')}</h3>
196→        <div className="w-8" />
197→      </div>
198→
199→      <div className="p-4 space-y-4">
200→        {/* Anomaly Banner */}
201→        {anomalies.length > 0 && (
202→          <div className="bg-red-50 border border-red-200 rounded-2xl p-4 flex items-start space-x-3">
203→            <AlertTriangle size={18} className="text-red-500 flex-shrink-0 mt-0.5" />
204→            <div>
205→              <p className="text-xs font-bold text-red-700">
206→                {anomalies.length} {t('Anomalies Detected', 'Anomalies detectees')}
207→              </p>
208→              <div className="mt-1 space-y-1">
209→                {anomalies.slice(0, 3).map((a, i) => (
210→                  <p key={i} className="text-[10px] text-red-600">
211→                    {a.vertical_id}: {a.anomaly_flags.map((f) => `${f.metric} z=${f.zScore}`).join(', ')}
212→                  </p>
213→                ))}
214→              </div>
215→            </div>
216→          </div>
217→        )}
218→
219→        {/* Summary Cards */}
220→        <div className="grid grid-cols-4 gap-2">
221→          <div className="bg-white p-3 rounded-2xl border border-gray-100 shadow-sm text-center">
222→            <span className="text-[9px] font-bold text-gray-400 uppercase tracking-widest block">{t('Points', 'Points')}</span>
223→            <span className="text-lg font-bold text-gray-900">{summaryTotalPoints}</span>
224→          </div>
225→          <div className="bg-white p-3 rounded-2xl border border-gray-100 shadow-sm text-center">
226→            <span className="text-[9px] font-bold text-gray-400 uppercase tracking-widest block">{t('WoW', 'WoW')}</span>
227→            <div className="flex items-center justify-center space-x-0.5">
228→              {summaryWoW !== null ? (
229→                <>
230→                  {summaryWoW > 0 ? <TrendingUp size={12} className="text-green-500" /> : summaryWoW < 0 ? <TrendingDown size={12} className="text-red-500" /> : <Minus size={12} className="text-gray-400" />}
231→                  <span className={`text-sm font-bold ${summaryWoW > 0 ? 'text-green-600' : summaryWoW < 0 ? 'text-red-600' : 'text-gray-500'}`}>
232→                    {summaryWoW > 0 ? '+' : ''}{summaryWoW}%
233→                  </span>
234→                </>
235→              ) : (
236→                <span className="text-sm text-gray-400">--</span>
237→              )}
238→            </div>
239→          </div>
240→          <div className="bg-white p-3 rounded-2xl border border-gray-100 shadow-sm text-center">
241→            <span className="text-[9px] font-bold text-gray-400 uppercase tracking-widest block">{t('Complete', 'Complet')}</span>
242→            <span className="text-sm font-bold text-gray-900">{summaryCompletion}%</span>
243→          </div>
244→          <div className="bg-white p-3 rounded-2xl border border-gray-100 shadow-sm text-center">
245→            <span className="text-[9px] font-bold text-gray-400 uppercase tracking-widest block">{t('Alerts', 'Alertes')}</span>
246→            <span className={`text-sm font-bold ${anomalies.length > 0 ? 'text-red-600' : 'text-gray-900'}`}>{anomalies.length}</span>
247→          </div>
248→        </div>
249→
250→        {/* Vertical Tabs */}
251→        <div className="flex overflow-x-auto space-x-2 no-scrollbar pb-1">
252→          <button
253→            onClick={() => setSelectedVertical('all')}
254→            className={`flex-shrink-0 px-3 py-1.5 rounded-xl text-[10px] font-bold uppercase tracking-wider transition-colors ${
255→              selectedVertical === 'all' ? 'bg-[#0f2b46] text-white' : 'bg-white text-gray-600 border border-gray-200'
256→            }`}
257→          >
258→            {t('All', 'Tout')}
259→          </button>
260→          {activeVerticals.map((vid) => (
261→            <button
262→              key={vid}
263→              onClick={() => setSelectedVertical(vid)}
264→              className={`flex-shrink-0 px-3 py-1.5 rounded-xl text-[10px] font-bold uppercase tracking-wider transition-colors ${
265→                selectedVertical === vid ? 'bg-[#0f2b46] text-white' : 'bg-white text-gray-600 border border-gray-200'
266→              }`}
267→            >
268→              {VERTICALS[vid]?.labelEn ?? vid}
269→            </button>
270→          ))}
271→        </div>
272→
273→        {loading ? (
274→          <div className="bg-white p-8 rounded-2xl border border-gray-100 shadow-sm text-center">
275→            <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">
276→              {t('Loading snapshot data...', 'Chargement des donnees...')}
277→            </p>
278→          </div>
279→        ) : stats.length === 0 ? (
280→          <div className="bg-white p-8 rounded-2xl border border-gray-100 shadow-sm text-center space-y-2">
281→            <p className="text-xs font-bold text-gray-600">
282→              {t('No snapshot data yet', 'Pas encore de donnees')}
283→            </p>
284→            <p className="text-[10px] text-gray-400">
285→              {t('Snapshots are taken weekly. Check back after the first run.', 'Les snapshots sont pris chaque semaine.')}
286→            </p>
287→          </div>
288→        ) : (
289→          <>
290→            {/* Point Count Trend */}
291→            {selectedVertical !== 'all' && trendData.length > 1 && (
292→              <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm space-y-3">
293→                <span className="text-[10px] font-bold text-gray-900 uppercase tracking-widest">
294→                  {t('Point Count Trend', 'Tendance des points')}
295→                </span>
296→                <div className="h-48 w-full">
297→                  <ResponsiveContainer width="100%" height="100%">
298→                    <LineChart data={trendData} margin={{ left: 0, right: 10, top: 5, bottom: 5 }}>
299→                      <XAxis dataKey="date" tick={{ fontSize: 9 }} tickFormatter={(d: string) => d.slice(5)} />
300→                      <YAxis tick={{ fontSize: 9 }} width={35} />
301→                      <Tooltip labelFormatter={(d: string) => d} />
302→                      <Line type="monotone" dataKey="value" stroke="#0f2b46" strokeWidth={2} dot={{ r: 3 }} name={t('Actual', 'Reel')} />
303→                      <Line type="monotone" dataKey="movingAvg" stroke="#4c7c59" strokeWidth={1.5} strokeDasharray="5 3" dot={false} name={t('4w Avg', 'Moy. 4s')} />
304→                      <Legend wrapperStyle={{ fontSize: 10 }} />
305→                    </LineChart>
306→                  </ResponsiveContainer>
307→                </div>
308→              </div>
309→            )}
310→
311→            {/* Delta Breakdown */}
312→            {deltaBreakdown.length > 0 && (
313→              <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm space-y-3">
314→                <span className="text-[10px] font-bold text-gray-900 uppercase tracking-widest">
315→                  {t('Delta Breakdown', 'Repartition des deltas')}
316→                </span>
317→                <div className="h-48 w-full">
318→                  <ResponsiveContainer width="100%" height="100%">
319→                    <BarChart data={deltaBreakdown} margin={{ left: 0, right: 10, top: 5, bottom: 5 }}>
320→                      <XAxis dataKey="date" tick={{ fontSize: 9 }} tickFormatter={(d: string) => d.slice(5)} />
321→                      <YAxis tick={{ fontSize: 9 }} width={35} />
322→                      <Tooltip />
323→                      <Bar dataKey="new" stackId="delta" fill="#22c55e" name={t('New', 'Nouveau')} />
324→                      <Bar dataKey="removed" stackId="delta" fill="#ef4444" name={t('Removed', 'Supprime')} />
325→                      <Bar dataKey="changed" stackId="delta" fill="#eab308" name={t('Changed', 'Modifie')} />
326→                      <Bar dataKey="unchanged" stackId="delta" fill="#d1d5db" name={t('Unchanged', 'Inchange')} />
327→                      <Legend wrapperStyle={{ fontSize: 10 }} />
328→                    </BarChart>
329→                  </ResponsiveContainer>
330→                </div>
331→              </div>
332→            )}
333→
334→            {/* Price Trend (fuel only) */}
335→            {showPriceTrend && priceTrend.length > 1 && (
336→              <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm space-y-3">
337→                <span className="text-[10px] font-bold text-gray-900 uppercase tracking-widest">
338→                  {t('Average Fuel Price', 'Prix moyen du carburant')}
339→                </span>
340→                <div className="h-40 w-full">
341→                  <ResponsiveContainer width="100%" height="100%">
342→                    <LineChart data={priceTrend} margin={{ left: 0, right: 10, top: 5, bottom: 5 }}>
343→                      <XAxis dataKey="date" tick={{ fontSize: 9 }} tickFormatter={(d: string) => d.slice(5)} />
344→                      <YAxis tick={{ fontSize: 9 }} width={45} />
345→                      <Tooltip labelFormatter={(d: string) => d} formatter={(v: number) => [`${v} XAF`, t('Price', 'Prix')]} />
346→                      <Line type="monotone" dataKey="price" stroke="#c86b4a" strokeWidth={2} dot={{ r: 3 }} />
347→                    </LineChart>
348→                  </ResponsiveContainer>
349→                </div>
350→              </div>
351→            )}
352→
353→            {/* Recent Deltas */}
354→            {selectedVertical !== 'all' && recentDeltas.length > 0 && (
355→              <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm space-y-3">
356→                <span className="text-[10px] font-bold text-gray-900 uppercase tracking-widest">
357→                  {t('Recent Changes', 'Changements recents')}
358→                </span>
359→                <div className="space-y-2 max-h-64 overflow-y-auto">
360→                  {recentDeltas.filter((d) => d.delta_type !== 'unchanged').slice(0, 15).map((delta) => (
361→                    <div key={delta.id} className="flex items-start space-x-2 p-2 bg-[#f9fafb] rounded-xl">
362→                      <span className={`text-[9px] font-bold uppercase tracking-wider px-1.5 py-0.5 rounded ${deltaTypeColor(delta.delta_type)}`}>
363→                        {deltaTypeLabel(delta.delta_type)}
364→                      </span>
365→                      <div className="flex-1 min-w-0">
366→                        <p className="text-[11px] text-gray-700 truncate">
367→                          {delta.delta_summary ?? `${delta.point_id.slice(0, 8)}...`}
368→                        </p>
369→                        {delta.delta_magnitude !== null && (
370→                          <p className="text-[10px] text-gray-400">
371→                            {delta.delta_direction === 'increase' ? '+' : ''}{delta.delta_magnitude}
372→                          </p>
373→                        )}
374→                      </div>
375→                    </div>
376→                  ))}
377→                </div>
378→              </div>
379→            )}
380→          </>
381→        )}
382→
383→        <div className="h-24" />
384→      </div>
385→    </div>
386→  );
387→};
388→
389→export default DeltaDashboard;
