 19→// ── Shared normalization helpers ────────────────────────────────────────
 20→
 21→function trimString(input: unknown): string | undefined {
 22→  if (typeof input !== "string") return undefined;
 23→  const trimmed = input.trim();
 24→  return trimmed || undefined;
 25→}
 26→
 27→function normalizeBoolean(input: unknown): boolean | undefined {
 28→  if (typeof input === "boolean") return input;
 29→  if (typeof input === "number") {
 30→    if (input === 1) return true;
 31→    if (input === 0) return false;
 32→    return undefined;
 33→  }
 34→  if (typeof input !== "string") return undefined;
 35→  const normalized = input.trim().toLowerCase();
 36→  if (!normalized) return undefined;
 37→  if (["true", "yes", "y", "1", "open", "available", "oui"].includes(normalized)) return true;
 38→  if (["false", "no", "n", "0", "closed", "unavailable", "non"].includes(normalized)) return false;
 39→  return undefined;
 40→}
 41→
 42→function normalizeProviders(input: unknown): string[] | undefined {
 43→  if (Array.isArray(input)) {
 44→    const list = input
 45→      .map((value) => trimString(value))
 46→      .filter((value): value is string => Boolean(value));
 47→    return list.length ? Array.from(new Set(list)) : undefined;
 48→  }
 49→  const single = trimString(input);
 50→  return single ? [single] : undefined;
 51→}
 52→
 53→/** Identity normalizer for verticals with no special normalization logic */
 54→function identityNormalize(d: SubmissionDetails): SubmissionDetails {
 55→  const details = { ...d };
 56→  const name = trimString(details.name) ?? trimString(details.siteName);
 57→  if (name) { details.name = name; details.siteName = name; }
 58→  const openingHours = trimString((details as Record<string, unknown>).opening_hours as string) ?? trimString(details.openingHours);
 59→  if (openingHours) details.openingHours = openingHours;
 60→  return details;
 61→}
 62→
 63→// ── Per-vertical normalizers ────────────────────────────────────────────
 64→
 65→function normalizePharmacy(d: SubmissionDetails): SubmissionDetails {
 66→  const details = identityNormalize(d);
 67→
 68→  if (typeof details.isOpenNow !== "boolean" && typeof details.availability === "string") {
 69→    const normalized = details.availability.toLowerCase();
 70→    details.isOpenNow = !normalized.includes("out") && !normalized.includes("closed");
 71→  }
 72→
 73→  const raw = details as Record<string, unknown>;
 74→  const isOnDuty = normalizeBoolean(raw.isOnDuty ?? raw.isOnCall ?? raw.onDuty ?? raw.pharmacyDeGarde);
 75→  if (typeof isOnDuty === "boolean") details.isOnDuty = isOnDuty;
 76→
 77→  if (typeof details.isOnDuty !== "boolean" && typeof details.availability === "string") {
 78→    const normalized = details.availability.toLowerCase();
 79→    if (normalized.includes("on-call") || normalized.includes("on call") || normalized.includes("garde")) {
 80→      details.isOnDuty = true;
 81→    }
 82→  }
 83→
 84→  return details;
 85→}
 86→
 87→function normalizeMobileMoney(d: SubmissionDetails): SubmissionDetails {
 88→  const details = identityNormalize(d);
 89→
 90→  const providers = normalizeProviders(details.providers ?? details.provider);
 91→  if (providers) details.providers = providers;
 92→
 93→  const cashThreshold =
 94→    normalizeBoolean(details.hasMin50000XafAvailable) ??
 95→    normalizeBoolean(details.hasCashAvailable) ??
 96→    (typeof details.availability === "string" ? !details.availability.toLowerCase().includes("out") : undefined);
 97→  if (typeof cashThreshold === "boolean") {
 98→    details.hasMin50000XafAvailable = cashThreshold;
 99→  }
100→  if ("hasCashAvailable" in details) {
101→    delete details.hasCashAvailable;
102→  }
103→  if (details.merchantId && providers?.length && !details.merchantIdByProvider) {
104→    details.merchantIdByProvider = { [providers[0]]: details.merchantId };
105→  }
106→
107→  return details;
108→}
109→
110→function normalizeFuelStation(d: SubmissionDetails): SubmissionDetails {
111→  const details = identityNormalize(d);
112→
113→  const fuelType = trimString(details.fuelType);
114→  if (fuelType && !details.fuelTypes?.length) details.fuelTypes = [fuelType];
115→
116→  const parsedPrice =
117→    typeof details.fuelPrice === "number"
118→      ? details.fuelPrice
119→      : typeof details.price === "number"
120→        ? details.price
121→        : undefined;
122→
123→  if (typeof details.hasFuelAvailable !== "boolean" && typeof details.availability === "string") {
124→    details.hasFuelAvailable = !details.availability.toLowerCase().includes("out");
125→  }
126→
127→  if (parsedPrice !== undefined) {
128→    const priceKey = fuelType ?? "super";
129→    details.pricesByFuel = { ...(details.pricesByFuel ?? {}), [priceKey]: parsedPrice };
130→    details.fuelPrice = parsedPrice;
131→    details.price = parsedPrice;
132→  }
133→
134→  return details;
135→}
