 1→export type IdentifierType = "email" | "phone";
 2→
 3→export interface NormalizedIdentifier {
 4→  type: IdentifierType;
 5→  value: string;
 6→}
 7→
 8→const DEFAULT_COUNTRY_CODE = "+237";
 9→const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
10→
11→function trimToNull(input: unknown): string | null {
12→  if (typeof input !== "string") return null;
13→  const trimmed = input.trim();
14→  return trimmed || null;
15→}
16→
17→function toDigits(input: string): string {
18→  return input.replace(/\D/g, "");
19→}
20→
21→export function normalizeEmail(input: unknown): string | null {
22→  const raw = trimToNull(input);
23→  if (!raw) return null;
24→  const normalized = raw.toLowerCase();
25→  if (!EMAIL_REGEX.test(normalized)) return null;
26→  return normalized;
27→}
28→
29→export function normalizePhone(input: unknown, defaultCountryCode = DEFAULT_COUNTRY_CODE): string | null {
30→  const raw = trimToNull(input);
31→  if (!raw) return null;
32→
33→  const compact = raw.replace(/[().\s-]/g, "");
34→  if (!compact) return null;
35→
36→  if (compact.startsWith("+")) {
37→    const digits = toDigits(compact);
38→    if (digits.length < 8 || digits.length > 15) return null;
39→    return `+${digits}`;
40→  }
41→
42→  if (compact.startsWith("00")) {
43→    const digits = toDigits(compact.slice(2));
44→    if (digits.length < 8 || digits.length > 15) return null;
45→    return `+${digits}`;
46→  }
47→
48→  const digits = toDigits(compact);
49→  if (!digits) return null;
50→
51→  if (digits.length === 12 && digits.startsWith("237")) {
52→    return `+${digits}`;
53→  }
54→
55→  if (digits.length === 9) {
56→    const prefix = defaultCountryCode.startsWith("+") ? defaultCountryCode : `+${defaultCountryCode}`;
57→    return `${prefix}${digits}`;
58→  }
59→
60→  if (digits.length >= 8 && digits.length <= 15) {
61→    return `+${digits}`;
62→  }
63→
64→  return null;
65→}
66→
67→export function normalizeIdentifier(input: unknown, defaultCountryCode = DEFAULT_COUNTRY_CODE): NormalizedIdentifier | null {
68→  const raw = trimToNull(input);
69→  if (!raw) return null;
70→
71→  const email = normalizeEmail(raw);
72→  if (email) {
73→    return { type: "email", value: email };
74→  }
75→
76→  const phone = normalizePhone(raw, defaultCountryCode);
77→  if (!phone) return null;
78→  return { type: "phone", value: phone };
79→}
80→
81→export function inferDefaultDisplayName(identifier: string): string {
82→  const email = normalizeEmail(identifier);
83→  if (email) {
84→    const at = email.indexOf("@");
85→    if (at > 0) return email.slice(0, at);
86→    return email;
87→  }
88→
89→  const phone = normalizePhone(identifier);
90→  if (!phone) return "Contributor";
91→  const digits = toDigits(phone);
92→  const suffix = digits.slice(-4);
93→  return suffix ? `Contributor ${suffix}` : "Contributor";
94→}
