208→function toFiniteNumber(input: unknown): number | null {
209→  if (typeof input === "number" && Number.isFinite(input)) return input;
210→  if (typeof input === "string") {
211→    const parsed = Number(input.trim());
212→    if (Number.isFinite(parsed)) return parsed;
