218→function toRationalNumber(input: unknown): number | null {
219→  const direct = toFiniteNumber(input);
220→  if (direct !== null) return direct;
221→  if (!input || typeof input !== "object") return null;
222→
223→  const rational = input as {
224→    numerator?: unknown;
225→    denominator?: unknown;
226→    num?: unknown;
227→    den?: unknown;
228→    value?: unknown;
229→  };
230→  const numerator = toFiniteNumber(rational.numerator ?? rational.num);
231→  const denominator = toFiniteNumber(rational.denominator ?? rational.den);
232→  if (numerator !== null && denominator !== null && denominator !== 0) {
233→    return numerator / denominator;
234→  }
235→  if ("value" in rational) return toRationalNumber(rational.value);
236→  return null;
237→}
