250→function applyHemisphere(value: number, ref: unknown, negativeChar: "S" | "W"): number {
251→  if (typeof ref !== "string") return value;
252→  const normalized = ref.trim().toUpperCase();
253→  if (!normalized) return value;
254→  if (normalized.startsWith(negativeChar)) return -Math.abs(value);
255→  return Math.abs(value);
256→}
