423→export function haversineKm(a: SubmissionLocation, b: SubmissionLocation): number {
424→  const toRad = (deg: number) => (deg * Math.PI) / 180;
425→  const dLat = toRad(b.latitude - a.latitude);
426→  const dLon = toRad(b.longitude - a.longitude);
427→  const lat1 = toRad(a.latitude);
428→  const lat2 = toRad(b.latitude);
429→  const sinLat = Math.sin(dLat / 2);
430→  const sinLon = Math.sin(dLon / 2);
431→  const h = sinLat * sinLat + Math.cos(lat1) * Math.cos(lat2) * sinLon * sinLon;
432→  return 2 * EARTH_RADIUS_KM * Math.atan2(Math.sqrt(h), Math.sqrt(1 - h));
433→}
