475→  const deviceMake = normalizeString(merged.Make);
476→  const deviceModel = normalizeString(merged.Model);
477→
478→  if (hasExifSignal({ gps, capturedAt, deviceMake, deviceModel })) {
479→    const exifStatus: SubmissionExifStatus = source === "remote_url" ? "fallback_recovered" : "ok";
480→    const exifReason = withContext(
481→      source === "remote_url" ? "Recovered EXIF metadata from stored photo URL" : "EXIF metadata parsed successfully",
482→      options,
483→    );
484→    return {
485→      gps,
486→      capturedAt,
487→      deviceMake,
488→      deviceModel,
489→      exifStatus,
490→      exifReason,
491→      exifSource: source,
492→    };
493→  }
494→
495→  const format = detectImageFormat(imageBuffer);
496→  const hasParseError = Boolean(exifAttempt.error || gpsAttempt.error);
497→  if (isUnsupportedExifFormat(format)) {
498→    return createExtractedPhotoMetadata(
499→      "unsupported_format",
500→      withContext(
501→        "Likely HEIC/HEIF metadata stripping or unsupported format. Enable iOS Camera Location and Most Compatible format",
502→        options,
503→      ),
504→      source,
505→    );
506→  }
507→  if (hasParseError) {
508→    return createExtractedPhotoMetadata(
509→      "parse_error",
510→      withContext("Unable to parse EXIF metadata from image bytes", options),
511→      source,
512→    );
513→  }
514→  return createExtractedPhotoMetadata(
515→    "missing",
516→    withContext(
517→      source === "remote_url" ? "No EXIF metadata found in stored photo bytes" : "No EXIF metadata found in uploaded file",
518→      options,
519→    ),
520→    source,
521→  );
522→}
523→
524→function isHttpUrl(input: string): boolean {
525→  return /^https?:\/\//i.test(input);
526→}
527→
528→export async function extractPhotoMetadataFromUrl(photoUrl: string): Promise<ExtractedPhotoMetadata | null> {
529→  if (!photoUrl || !isHttpUrl(photoUrl)) return null;
530→
531→  const source: ExtractPhotoMetadataSource = "remote_url";
532→  const controller = new AbortController();
533→  const timeout = setTimeout(() => controller.abort(), REMOTE_FETCH_TIMEOUT_MS);
534→  try {
535→    const response = await fetch(photoUrl, { signal: controller.signal });
536→    const mime = normalizeString(response.headers.get("content-type"));
537→    const ext = inferRemoteExt(photoUrl);
538→    if (!response.ok) {
539→      return createExtractedPhotoMetadata(
540→        "parse_error",
541→        withContext(`Unable to fetch remote photo for EXIF recovery (HTTP ${response.status})`, { source, mime, ext }),
542→        source,
543→      );
544→    }
545→    const arrayBuffer = await response.arrayBuffer();
546→    const byteLength = arrayBuffer.byteLength;
547→    if (!byteLength) {
548→      return createExtractedPhotoMetadata(
549→        "missing",
550→        withContext("Remote photo is empty; EXIF recovery skipped", { source, mime, ext, byteLength }),
551→        source,
552→      );
553→    }
554→    if (byteLength > MAX_REMOTE_METADATA_BYTES) {
555→      return createExtractedPhotoMetadata(
556→        "parse_error",
557→        withContext(`Remote photo exceeds EXIF fetch limit (${MAX_REMOTE_METADATA_BYTES} bytes)`, {
558→          source,
559→          mime,
560→          ext,
561→          byteLength,
562→        }),
563→        source,
564→      );
565→    }
566→    return await extractPhotoMetadata(Buffer.from(arrayBuffer), { source, mime, ext, byteLength });
567→  } catch (error) {
568→    const timeoutMessage = error instanceof Error && error.name === "AbortError";
569→    const reason = timeoutMessage
570→      ? `Timed out fetching remote photo after ${REMOTE_FETCH_TIMEOUT_MS}ms`
571→      : "Unable to fetch remote photo for EXIF recovery";
572→    return createExtractedPhotoMetadata("parse_error", withContext(reason, { source, ext: inferRemoteExt(photoUrl) }), source);
573→  } finally {
574→    clearTimeout(timeout);
575→  }
576→}
577→
578→export function applyClientExifFallback(
579→  metadata: ExtractedPhotoMetadata,
580→  clientExif: ClientExifData | null | undefined,
581→): ExtractedPhotoMetadata {
582→  if (!clientExif) return metadata;
583→  if (hasExifSignal(metadata)) return metadata;
584→
585→  const gps: SubmissionLocation | null =
586→    typeof clientExif.latitude === "number" &&
587→    typeof clientExif.longitude === "number" &&
588→    Number.isFinite(clientExif.latitude) &&
589→    Number.isFinite(clientExif.longitude)
590→      ? { latitude: clientExif.latitude, longitude: clientExif.longitude }
591→      : null;
592→
593→  const capturedAt = typeof clientExif.capturedAt === "string" && clientExif.capturedAt.trim() ? clientExif.capturedAt.trim() : null;
594→  const deviceMake = typeof clientExif.deviceMake === "string" && clientExif.deviceMake.trim() ? clientExif.deviceMake.trim() : null;
595→  const deviceModel = typeof clientExif.deviceModel === "string" && clientExif.deviceModel.trim() ? clientExif.deviceModel.trim() : null;
596→
597→  if (!gps && !capturedAt && !deviceMake && !deviceModel) return metadata;
598→
599→  return {
600→    gps,
601→    capturedAt,
602→    deviceMake,
603→    deviceModel,
604→    exifStatus: "fallback_recovered",
605→    exifReason: `EXIF recovered from client-side extraction (server got ${metadata.exifStatus}: ${metadata.exifReason ?? "no details"})`,
606→    exifSource: "upload_buffer",
607→  };
608→}
609→
610→export function buildPhotoFraudMetadata(params: BuildPhotoFraudMetadataParams): SubmissionPhotoMetadata | null {
611→  if (!params.extracted) return null;
612→
613→  const { extracted, submissionLocation, ipLocation, submissionMatchThresholdKm, ipMatchThresholdKm } = params;
614→  const gps = extracted.gps;
615→
616→  const submissionDistanceRaw = gps && submissionLocation ? haversineKm(submissionLocation, gps) : null;
617→  const ipDistanceRaw = gps && ipLocation ? haversineKm(ipLocation, gps) : null;
618→
619→  const submissionDistanceKm = submissionDistanceRaw === null ? null : roundKm(submissionDistanceRaw);
620→  const ipDistanceKm = ipDistanceRaw === null ? null : roundKm(ipDistanceRaw);
621→
622→  return {
623→    gps,
624→    capturedAt: extracted.capturedAt,
625→    deviceMake: extracted.deviceMake,
626→    deviceModel: extracted.deviceModel,
627→    submissionDistanceKm,
628→    submissionGpsMatch: submissionDistanceKm === null ? null : submissionDistanceKm <= submissionMatchThresholdKm,
629→    ipDistanceKm,
630→    ipGpsMatch: ipDistanceKm === null ? null : ipDistanceKm <= ipMatchThresholdKm,
631→    exifStatus: extracted.exifStatus,
632→    exifReason: extracted.exifReason,
633→    exifSource: extracted.exifSource,
634→  };
635→}
636→
637→export function buildSubmissionFraudCheck(params: BuildSubmissionFraudCheckParams): SubmissionFraudCheck {
638→  return {
639→    submissionLocation: params.submissionLocation,
640→    effectiveLocation: params.effectiveLocation,
641→    ipLocation: params.ipLocation,
642→    primaryPhoto: params.primaryPhoto,
643→    secondaryPhoto: params.secondaryPhoto,
644→    submissionMatchThresholdKm: params.submissionMatchThresholdKm,
645→    ipMatchThresholdKm: params.ipMatchThresholdKm,
646→  };
647→}
648→
649→function parsePhotoFraudMetadata(input: unknown): SubmissionPhotoMetadata | null {
650→  if (!input || typeof input !== "object") return null;
651→  const metadata = input as Record<string, unknown>;
652→
653→  const parsed: SubmissionPhotoMetadata = {
654→    gps: parseLocation(metadata.gps),
655→    capturedAt: parseDateIso(metadata.capturedAt),
656→    deviceMake: normalizeString(metadata.deviceMake),
657→    deviceModel: normalizeString(metadata.deviceModel),
658→    submissionDistanceKm: parseOptionalNumber(metadata.submissionDistanceKm),
659→    submissionGpsMatch: parseOptionalBoolean(metadata.submissionGpsMatch),
660→    ipDistanceKm: parseOptionalNumber(metadata.ipDistanceKm),
661→    ipGpsMatch: parseOptionalBoolean(metadata.ipGpsMatch),
662→    exifStatus: "missing",
663→    exifReason: normalizeString(metadata.exifReason),
664→    exifSource: parseExifSource(metadata.exifSource) ?? "none",
665→  };
666→
667→  const explicitStatus = parseExifStatus(metadata.exifStatus);
668→  if (explicitStatus) {
669→    parsed.exifStatus = explicitStatus;
670→  } else if (hasExifSignal(parsed)) {
671→    parsed.exifStatus = "ok";
672→  } else {
673→    parsed.exifStatus = "missing";
674→  }
675→
676→  return parsed;
677→}
678→
679→export function parseSubmissionFraudCheck(input: unknown): SubmissionFraudCheck | null {
680→  if (!input || typeof input !== "object") return null;
681→  const fraudCheck = input as Record<string, unknown>;
682→  const effectiveLocation = parseLocation(fraudCheck.effectiveLocation);
683→  if (!effectiveLocation) return null;
684→
685→  const submissionMatchThresholdKm =
686→    parseOptionalNumber(fraudCheck.submissionMatchThresholdKm) ?? DEFAULT_SUBMISSION_GPS_MATCH_THRESHOLD_KM;
687→  const ipMatchThresholdKm = parseOptionalNumber(fraudCheck.ipMatchThresholdKm) ?? 50;
688→
689→  return {
690→    submissionLocation: parseLocation(fraudCheck.submissionLocation),
691→    effectiveLocation,
692→    ipLocation: parseLocation(fraudCheck.ipLocation),
693→    primaryPhoto: parsePhotoFraudMetadata(fraudCheck.primaryPhoto),
694→    secondaryPhoto: parsePhotoFraudMetadata(fraudCheck.secondaryPhoto),
695→    submissionMatchThresholdKm,
696→    ipMatchThresholdKm,
697→  };
698→}
