  1→import type { SubmissionInput } from '../../shared/types';
  2→
  3→const DB_NAME = 'adl_offline_queue';
  4→const STORE_NAME = 'submission_queue';
  5→const SYNC_ERROR_STORE_NAME = 'submission_sync_errors';
  6→const DB_VERSION = 2;
  7→
  8→export type QueueStatus = 'pending' | 'syncing' | 'failed' | 'synced';
  9→
 10→export interface QueueItem {
 11→  id: string;
 12→  idempotencyKey: string;
 13→  payload: SubmissionInput;
 14→  status: QueueStatus;
 15→  attempts: number;
 16→  retryCount: number;
 17→  nextRetryAt?: string;
 18→  lastError?: string;
 19→  createdAt: string;
 20→  updatedAt: string;
 21→}
 22→
 23→export interface SyncErrorRecord {
 24→  id: string;
 25→  queueItemId: string;
 26→  message: string;
 27→  createdAt: string;
 28→  payloadSummary: {
 29→    eventType: SubmissionInput['eventType'];
 30→    category: SubmissionInput['category'];
 31→    pointId?: string;
 32→    location?: SubmissionInput['location'];
 33→  };
 34→}
 35→
 36→export interface QueueSyncSummary {
 37→  synced: number;
 38→  failed: number;
 39→  syncedIds: string[];
 40→  failedIds: string[];
 41→  permanentFailures: number;
 42→  permanentFailureIds: string[];
 43→  permanentFailureMessages: string[];
 44→  remaining: number;
 45→}
 46→
 47→function toQueueErrorInfo(error: unknown): { message: string; retryable: boolean } {
 48→  const fallback = 'Unable to sync queued submission';
 49→  if (error instanceof Error) {
 50→    const withRetryable = error as Error & { retryable?: unknown };
 51→    const retryable = typeof withRetryable.retryable === 'boolean' ? withRetryable.retryable : true;
 52→    const message = error.message?.trim() || fallback;
 53→    return { message, retryable };
 54→  }
 55→  return { message: String(error ?? fallback), retryable: true };
 56→}
 57→
 58→function ensureIndexedDb(): IDBFactory {
 59→  if (typeof indexedDB === 'undefined') {
 60→    throw new Error('IndexedDB is not available');
 61→  }
 62→  return indexedDB;
 63→}
 64→
 65→function requestToPromise<T>(request: IDBRequest<T>): Promise<T> {
 66→  return new Promise((resolve, reject) => {
 67→    request.onsuccess = () => resolve(request.result);
 68→    request.onerror = () => reject(request.error);
 69→  });
 70→}
 71→
 72→function transactionDone(tx: IDBTransaction): Promise<void> {
 73→  return new Promise((resolve, reject) => {
 74→    tx.oncomplete = () => resolve();
 75→    tx.onerror = () => reject(tx.error);
 76→    tx.onabort = () => reject(tx.error ?? new Error('IndexedDB transaction aborted'));
 77→  });
 78→}
 79→
 80→async function openDb(): Promise<IDBDatabase> {
 81→  const db = ensureIndexedDb();
 82→  return await new Promise<IDBDatabase>((resolve, reject) => {
 83→    const request = db.open(DB_NAME, DB_VERSION);
 84→    request.onupgradeneeded = () => {
 85→      const nextDb = request.result;
 86→      if (!nextDb.objectStoreNames.contains(STORE_NAME)) {
 87→        nextDb.createObjectStore(STORE_NAME, { keyPath: 'id' });
 88→      }
 89→      if (!nextDb.objectStoreNames.contains(SYNC_ERROR_STORE_NAME)) {
 90→        nextDb.createObjectStore(SYNC_ERROR_STORE_NAME, { keyPath: 'id' });
 91→      }
 92→    };
 93→    request.onsuccess = () => resolve(request.result);
 94→    request.onerror = () => reject(request.error);
 95→  });
 96→}
 97→
 98→async function putItem(item: QueueItem): Promise<void> {
 99→  const db = await openDb();
100→  const tx = db.transaction(STORE_NAME, 'readwrite');
101→  tx.objectStore(STORE_NAME).put(item);
102→  await transactionDone(tx);
103→  db.close();
104→}
105→
106→export async function enqueueSubmission(payload: SubmissionInput): Promise<QueueItem> {
107→  const now = new Date().toISOString();
108→  const item: QueueItem = {
109→    id: crypto.randomUUID(),
110→    idempotencyKey: crypto.randomUUID(),
111→    payload,
112→    status: 'pending',
113→    attempts: 0,
114→    retryCount: 0,
115→    createdAt: now,
116→    updatedAt: now
117→  };
118→  await putItem(item);
119→  return item;
120→}
121→
122→export async function listQueueItems(): Promise<QueueItem[]> {
123→  const db = await openDb();
124→  const tx = db.transaction(STORE_NAME, 'readonly');
125→  const request = tx.objectStore(STORE_NAME).getAll();
126→  const result = await requestToPromise(request);
127→  await transactionDone(tx);
128→  db.close();
129→  return (result as QueueItem[]).sort((a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime());
130→}
131→
132→async function updateItem(id: string, updater: (item: QueueItem) => QueueItem): Promise<QueueItem | null> {
133→  const db = await openDb();
134→  return await new Promise<QueueItem | null>((resolve, reject) => {
135→    const tx = db.transaction(STORE_NAME, 'readwrite');
136→    const store = tx.objectStore(STORE_NAME);
137→    let updated: QueueItem | null = null;
138→    const getRequest = store.get(id);
139→    getRequest.onsuccess = () => {
140→      const existing = getRequest.result as QueueItem | undefined;
141→      if (!existing) return;
142→      updated = updater(existing);
143→      store.put(updated);
144→    };
145→    getRequest.onerror = () => reject(getRequest.error);
146→    tx.oncomplete = () => {
147→      db.close();
148→      resolve(updated);
149→    };
150→    tx.onerror = () => {
151→      db.close();
152→      reject(tx.error);
153→    };
154→    tx.onabort = () => {
155→      db.close();
156→      reject(tx.error ?? new Error('IndexedDB transaction aborted'));
157→    };
158→  });
159→}
160→
161→async function removeItem(id: string): Promise<void> {
162→  const db = await openDb();
163→  const tx = db.transaction(STORE_NAME, 'readwrite');
164→  tx.objectStore(STORE_NAME).delete(id);
165→  await transactionDone(tx);
166→  db.close();
167→}
168→
169→async function putSyncErrorRecord(record: SyncErrorRecord): Promise<void> {
170→  const db = await openDb();
171→  const tx = db.transaction(SYNC_ERROR_STORE_NAME, 'readwrite');
172→  tx.objectStore(SYNC_ERROR_STORE_NAME).put(record);
173→  await transactionDone(tx);
174→  db.close();
175→}
176→
177→export async function listSyncErrorRecords(): Promise<SyncErrorRecord[]> {
178→  const db = await openDb();
179→  const tx = db.transaction(SYNC_ERROR_STORE_NAME, 'readonly');
180→  const request = tx.objectStore(SYNC_ERROR_STORE_NAME).getAll();
181→  const result = await requestToPromise(request);
182→  await transactionDone(tx);
183→  db.close();
184→  return (result as SyncErrorRecord[]).sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
185→}
186→
187→export async function clearSyncErrorRecords(): Promise<void> {
188→  const db = await openDb();
189→  const tx = db.transaction(SYNC_ERROR_STORE_NAME, 'readwrite');
190→  tx.objectStore(SYNC_ERROR_STORE_NAME).clear();
191→  await transactionDone(tx);
192→  db.close();
193→}
194→
195→export async function getQueueStats(): Promise<{ pending: number; failed: number; total: number }> {
196→  const items = await listQueueItems();
197→  return {
198→    pending: items.filter((item) => item.status === 'pending' || item.status === 'syncing').length,
199→    failed: items.filter((item) => item.status === 'failed').length,
200→    total: items.length
201→  };
202→}
203→
204→export async function flushOfflineQueue(
205→  sendFn: (payload: SubmissionInput, options?: { idempotencyKey?: string }) => Promise<void>,
206→): Promise<QueueSyncSummary> {
207→  const items = await listQueueItems();
208→  const now = Date.now();
209→  let synced = 0;
210→  let failed = 0;
211→  const syncedIds: string[] = [];
212→  const failedIds: string[] = [];
213→  let permanentFailures = 0;
214→  const permanentFailureIds: string[] = [];
215→  const permanentFailureMessages = new Set<string>();
216→
217→  for (const item of items) {
218→    // Skip items not yet ready for retry (exponential backoff).
219→    if (item.nextRetryAt && new Date(item.nextRetryAt).getTime() > now) {
220→      failed += 1;
221→      failedIds.push(item.id);
222→      continue;
223→    }
224→
225→    await updateItem(item.id, (current) => ({
226→      ...current,
227→      status: 'syncing',
228→      attempts: current.attempts + 1,
229→      updatedAt: new Date().toISOString()
230→    }));
231→
232→    try {
233→      await sendFn(item.payload, { idempotencyKey: item.idempotencyKey });
234→      await removeItem(item.id);
235→      synced += 1;
236→      syncedIds.push(item.id);
237→    } catch (error) {
238→      const details = toQueueErrorInfo(error);
239→      if (details.retryable) {
240→        failed += 1;
241→        failedIds.push(item.id);
242→        const retryCount = (item.retryCount ?? 0) + 1;
243→        const baseDelay = Math.min(30000, 1000 * Math.pow(2, retryCount));
244→        const jitter = Math.random() * 1000;
245→        const nextRetryAt = new Date(now + baseDelay + jitter).toISOString();
246→        await updateItem(item.id, (current) => ({
247→          ...current,
248→          status: 'failed',
249→          retryCount,
250→          nextRetryAt,
251→          updatedAt: new Date().toISOString(),
252→          lastError: details.message,
253→        }));
254→        continue;
255→      }
256→
257→      permanentFailures += 1;
258→      permanentFailureIds.push(item.id);
259→      permanentFailureMessages.add(details.message);
260→      await putSyncErrorRecord({
261→        id: crypto.randomUUID(),
262→        queueItemId: item.id,
263→        message: details.message,
264→        createdAt: new Date().toISOString(),
265→        payloadSummary: {
266→          eventType: item.payload.eventType,
267→          category: item.payload.category,
268→          pointId: item.payload.pointId,
269→          location: item.payload.location,
270→        },
271→      });
272→      await removeItem(item.id);
273→    }
274→  }
275→
276→  const remaining = (await listQueueItems()).length;
277→  return {
278→    synced,
279→    failed,
280→    syncedIds,
281→    failedIds,
282→    permanentFailures,
283→    permanentFailureIds,
284→    permanentFailureMessages: Array.from(permanentFailureMessages),
285→    remaining,
286→  };
287→}
