 40→function normalizeEventId(input: string): string {
 41→  const trimmed = input.trim();
 42→  if (isUuid(trimmed)) return trimmed.toLowerCase();
 43→  return deterministicUuid(`event:${trimmed}`);
 44→}
 45→
 46→function normalizeCreatedAt(input: unknown): string {
 47→  if (typeof input === "string") {
 48→    const parsed = new Date(input);
 49→    if (!Number.isNaN(parsed.getTime())) return parsed.toISOString();
 50→  }
 51→  return new Date().toISOString();
 52→}
