161→async function upsertUserProfileLegacy(params: {
162→  id: string;
163→  email: string | null;
164→  name: string;
165→  image: string;
166→  occupation: string;
167→  xp: number;
168→  passwordHash: string | null;
169→  isAdmin: boolean;
