 17→export async function GET(request: Request): Promise<Response> {
 18→  const url = new URL(request.url);
 19→  const view = url.searchParams.get("view") ?? "snapshots";
 20→
 21→  // Cron trigger — authenticated via CRON_SECRET, not user session
 22→  if (view === "cron") {
 23→    const authHeader = request.headers.get("authorization");
 24→    const cronSecret = process.env.CRON_SECRET;
 25→    if (!cronSecret || authHeader !== `Bearer ${cronSecret}`) {
 26→      return errorResponse("Unauthorized", 401);
 27→    }
 28→    try {
 29→      const { runWeeklySnapshot } = await import("../../lib/server/snapshotEngine.js");
 30→      const dateOverride = url.searchParams.get("date") ?? undefined;
 31→      const result = await runWeeklySnapshot(dateOverride);
 32→      return jsonResponse(result);
 33→    } catch (error) {
 34→      console.error("Snapshot cron failed:", error);
 35→      return errorResponse(
 36→        error instanceof Error ? error.message : "Snapshot failed",
 37→        500,
 38→      );
 39→    }
 40→  }
 41→
 42→  // All other views require authenticated user
 43→  const user = await requireUser(request);
 44→  if (!user) return errorResponse("Unauthorized", 401);
 45→
 46→  switch (view) {
 47→    case "snapshots":
 48→      return handleSnapshots(url);
 49→    case "deltas":
 50→      return handleDeltas(url);
 51→    case "trends":
 52→      return handleTrends(url);
 53→    case "anomalies":
 54→      return handleAnomalies();
 55→    default:
 56→      return errorResponse(`Invalid view: ${view}. Valid: snapshots, deltas, trends, anomalies, cron`, 400);
 57→  }
 58→}
