 60→async function handleSnapshots(url: URL): Promise<Response> {
 61→  const vertical = url.searchParams.get("vertical");
 62→  const limit = Math.min(parseInt(url.searchParams.get("limit") ?? "12", 10), 52);
 63→
 64→  const conditions: string[] = [];
 65→  const values: unknown[] = [];
 66→  let idx = 1;
 67→
 68→  if (vertical) {
 69→    conditions.push(`vertical_id = $${idx++}`);
 70→    values.push(vertical);
 71→  }
 72→
 73→  const where = conditions.length > 0 ? `WHERE ${conditions.join(" AND ")}` : "";
 74→  values.push(limit);
 75→
 76→  const result = await query(
 77→    `SELECT * FROM snapshot_stats ${where} ORDER BY snapshot_date DESC, vertical_id LIMIT $${idx}`,
 78→    values,
 79→  );
 80→
 81→  return jsonResponse(result.rows);
 82→}
