 84→async function handleDeltas(url: URL): Promise<Response> {
 85→  const date = url.searchParams.get("date");
 86→  const vertical = url.searchParams.get("vertical");
 87→  const type = url.searchParams.get("type");
 88→  const limit = Math.min(parseInt(url.searchParams.get("limit") ?? "100", 10), 500);
 89→
 90→  const conditions: string[] = [];
 91→  const values: unknown[] = [];
 92→  let idx = 1;
 93→
 94→  if (date) {
 95→    conditions.push(`snapshot_date = $${idx++}`);
 96→    values.push(date);
 97→  }
 98→  if (vertical) {
 99→    conditions.push(`vertical_id = $${idx++}`);
100→    values.push(vertical);
101→  }
102→  if (type) {
103→    conditions.push(`delta_type = $${idx++}`);
104→    values.push(type);
105→  }
106→
107→  const where = conditions.length > 0 ? `WHERE ${conditions.join(" AND ")}` : "";
108→
109→  const [dataResult, countResult] = await Promise.all([
110→    query(
111→      `SELECT * FROM snapshot_deltas ${where} ORDER BY snapshot_date DESC, delta_type, point_id LIMIT $${idx}`,
112→      [...values, limit],
113→    ),
114→    query(
115→      `SELECT COUNT(*)::int AS total FROM snapshot_deltas ${where}`,
116→      values,
117→    ),
118→  ]);
119→
120→  return jsonResponse({
121→    deltas: dataResult.rows,
122→    total: (countResult.rows[0] as { total: number }).total,
123→  });
124→}
