126→async function handleTrends(url: URL): Promise<Response> {
127→  const vertical = url.searchParams.get("vertical");
128→  const metric = url.searchParams.get("metric") ?? "total_points";
129→  const weeks = Math.min(parseInt(url.searchParams.get("weeks") ?? "12", 10), 52);
130→
131→  if (!VALID_METRICS.has(metric)) {
132→    return errorResponse(`Invalid metric. Valid: ${[...VALID_METRICS].join(", ")}`, 400);
133→  }
134→
135→  if (!vertical) {
136→    return errorResponse("vertical parameter is required", 400);
137→  }
138→
139→  const result = await query<{ snapshot_date: string; [key: string]: unknown }>(
140→    `SELECT snapshot_date, ${metric} FROM snapshot_stats
141→     WHERE vertical_id = $1
142→     ORDER BY snapshot_date DESC
143→     LIMIT $2`,
144→    [vertical, weeks],
145→  );
146→
147→  const rows = result.rows.reverse();
148→  const values = rows.map((r) => Number(r[metric]) || 0);
149→
150→  const data = rows.map((row, i) => ({
151→    date: row.snapshot_date,
152→    value: Number(row[metric]) || 0,
153→    movingAvg: computeMovingAverage(values.slice(0, i + 1), 4),
154→  }));
155→
156→  return jsonResponse({ data });
157→}
