159→async function handleAnomalies(): Promise<Response> {
160→  const result = await query(
161→    `SELECT snapshot_date, vertical_id, total_points, anomaly_flags
162→     FROM snapshot_stats
163→     WHERE jsonb_array_length(anomaly_flags) > 0
164→     ORDER BY snapshot_date DESC
165→     LIMIT 50`,
166→  );
167→
168→  return jsonResponse(result.rows);
169→}
